parameters.jsCode:
/**
 * HTML TO CART_STATE NORMALIZER
 *
 * PURPOSE:
 *   Transform HTML frontend payload into canonical CART_STATE format.
 *
 * INPUT (HTML Payload):
 *   { customer_name, email, phone, order_items[], subtotal, tax, total, pickup_time, special_instructions }
 *
 * OUTPUT (Canonical CART_STATE):
 *   { cart_id, status, customer_name, customer_email, customer_phone,
 *     cart_items[], cart_items_json, subtotal_cents, tax_cents, total_cents,
 *     created_at, updated_at, source: "html" }
 */

const input = $json.payload || $json;

// 1. Generate cart_id
const now = new Date();
const date = now.toISOString().slice(0, 10).replace(/-/g, "");
const random = Math.floor(Math.random() * 900) + 100;
const cartId = "UDO-" + date + "-" + random;

// 2. Transform order_items → cart_items
const orderItems = Array.isArray(input.order_items) ? input.order_items : [];

const cartItems = orderItems.map(function(item, idx) {
  const qty = Number(item.qty || 1);
  const priceDollars = Number(item.price || 0);
  const basePriceCents = Math.round(priceDollars * 100);

  // Parse modifiers from string array to structured objects
  const rawModifiers = Array.isArray(item.modifiers) ? item.modifiers : [];
  const modifiers = rawModifiers.map(function(modStr) {
    const trimmed = String(modStr).trim();

    // Detect add-ons: "+ Addon Name ($0.50)"
    const addonMatch = trimmed.match(/^\+\s+(.+?)\s*\(\$?([\d.]+)\)$/);
    if (addonMatch) {
      return { mod_name: trimmed, price_delta: Number(addonMatch[2]) };
    }

    // Detect take-offs
    if (/^(no\s|no-|hold\s|hold-)/i.test(trimmed)) {
      return { mod_name: trimmed, price_delta: 0 };
    }

    // Everything else = identifier/choice ($0)
    return { mod_name: trimmed, price_delta: 0 };
  });

  // Calculate line total
  const addonTotalCents = modifiers.reduce(function(sum, m) {
    return sum + Math.round(Number(m.price_delta || 0) * 100 * qty);
  }, 0);
  const lineTotalCents = (basePriceCents * qty) + addonTotalCents;

  return {
    type: "primary",
    display_name: item.name || "Item " + (idx + 1),
    quantity: qty,
    base_price_cents: basePriceCents,
    variant_price_cents: 0,
    modifiers: modifiers,
    notes: item.notes || "",
    line_total_cents: lineTotalCents
  };
});

// 3. Compute canonical totals in cents
const subtotalCents = Math.round(Number(input.subtotal || 0) * 100);
const taxCents = Math.round(Number(input.tax || 0) * 100);
const totalCents = Math.round(Number(input.total || 0) * 100);

// Validate: subtotal + tax == total
if (subtotalCents + taxCents !== totalCents) {
  throw new Error(
    "TOTAL_MISMATCH: subtotal (" + subtotalCents + ") + tax (" + taxCents +
    ") != total (" + totalCents + ")"
  );
}

// 4. Build canonical CART_STATE
const cartState = {
  cart_id: cartId,
  status: "OPEN",
  customer_name: input.customer_name || "",
  customer_email: input.email || "",
  customer_phone: input.phone || "",
  cart_items: cartItems,
  cart_items_json: JSON.stringify(cartItems),
  subtotal_cents: subtotalCents,
  tax_cents: taxCents,
  total_cents: totalCents,
  created_at: now.toISOString(),
  updated_at: now.toISOString(),
  source: "html"
};

// 5. Build Square line items
const squareLineItems = cartItems.map(function(item) {
  const lineItem = {
    name: item.display_name,
    quantity: String(item.quantity),
    base_price_money: { amount: item.base_price_cents, currency: "USD" },
    modifiers: []
  };

  if (Array.isArray(item.modifiers)) {
    item.modifiers.forEach(function(mod) {
      lineItem.modifiers.push({
        name: mod.mod_name,
        base_price_money: { amount: Math.round(Number(mod.price_delta || 0) * 100), currency: "USD" }
      });
    });
  }

  return lineItem;
});

// Add tax as separate line item
if (taxCents > 0) {
  squareLineItems.push({
    name: "Tax",
    quantity: "1",
    base_price_money: { amount: taxCents, currency: "USD" }
  });
}

// 6. Output
return {
  ...cartState,
  square_line_items: squareLineItems,
  square_line_items_with_tax: squareLineItems,
  pickup_time: input.pickup_time || "",
  special_instructions: input.special_instructions || ""
};

const input = $json;

// Resolve cart_items safely
let cart_items = input.cart_items;

if (!Array.isArray(cart_items)) {
  if (typeof input.cart_items_json === "string") {
    try {
      cart_items = JSON.parse(input.cart_items_json);
    } catch {
      throw new Error("cart_items_json is invalid JSON");
    }
  }
}

if (!Array.isArray(cart_items)) {
  throw new Error("cart_html builder requires cart_items or cart_items_json");
}

// Helpers
const money = cents =>"$" + (Number(cents || 0) / 100).toFixed(2);

const isTakeOff = mod =>
  typeof mod?.mod_name === "string" &&
  /^(no\s|no-|hold\s|hold-)/i.test(mod.mod_name.trim());

const sanitizeText = txt => String(txt).replace(/[<>]/g, "");

const BRAND_MUTED = "#555";
const BRAND_SUBTLE = "#777";

// Build cart rows
let rows = "";

cart_items.forEach(function(item, idx) {
  const qty = Number(item.quantity || 1);
  const baseUnitCents = Number(item.base_price_cents || 0) + Number(item.variant_price_cents || 0);
  const baseDisplayCents = baseUnitCents * qty;
  const modifiers = Array.isArray(item.modifiers) ? item.modifiers : [];

  const identifiers = modifiers.filter(m => !isTakeOff(m) && Number(m.price_delta) === 0);
  const takeoffs = modifiers.filter(isTakeOff);
  const addons = modifiers.filter(m => !isTakeOff(m) && Number(m.price_delta) > 0);

  if (idx > 0) {
    rows += "<tr><td colspan=\"2\" style=\"padding-top:14px;\"></td></tr>";
  }

  // Item header
  rows += "<tr><td><strong>" + (qty > 1 ? qty + " × " : "") + item.display_name + "</strong></td><td style=\"text-align:right;\"><strong>" + money(baseDisplayCents) + "</strong></td></tr>";

  // Identifiers
  identifiers.forEach(m => {
    rows += "<tr><td style=\"padding-left:24px; font-style:italic;\">" + m.mod_name + "</td><td></td></tr>";
  });

  // Take-offs
  if (takeoffs.length > 0) {
    rows += "<tr><td colspan=\"2\" style=\"padding-left:24px; font-size:11px; font-weight:600; color:" + BRAND_MUTED + "; padding-top:4px;\">TAKE OFF</td></tr>";
  }
  takeoffs.forEach(m => {
    rows += "<tr><td style=\"padding-left:24px; font-style:italic; color:" + BRAND_MUTED + ";\">" + m.mod_name + "</td><td></td></tr>";
  });

  // Add-ons
  if (addons.length > 0) {
    rows += "<tr><td colspan=\"2\" style=\"padding-left:24px; font-size:11px; font-weight:600; color:" + BRAND_MUTED + "; padding-top:6px;\">ADD‑ONS</td></tr>";
  }
  addons.forEach(m => {
    rows += "<tr><td style=\"padding-left:24px;\">+ " + m.mod_name + "</td><td style=\"text-align:right;\">" + money(Number(m.price_delta) * 100) + "</td></tr>";
  });

  // Notes
  if (item.notes && String(item.notes).trim()) {
    const safeNote = sanitizeText(item.notes);
    rows += "<tr><td colspan=\"2\" style=\"padding-left:24px; font-style:italic; color:" + BRAND_MUTED + "; padding-top:6px;\">Notes: " + safeNote + "</td></tr>";
  }

  // Item total
  if (addons.length > 0 && item.line_total_cents) {
    rows += "<tr><td style=\"padding-left:24px; font-weight:600;\">Item total</td><td style=\"text-align:right; font-weight:600;\">" + money(item.line_total_cents) + "</td></tr>";
  }
});

// Final cart HTML
const cart_html = "<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">" +
  rows +
  "<tr><td colspan=\"2\"><hr></td></tr>" +
  "<tr><td><strong>Subtotal</strong></td><td style=\"text-align:right;\"><strong>" + money(input.subtotal_cents) + "</strong></td></tr>" +
  "<tr><td>Tax</td><td style=\"text-align:right;\">" + money(input.tax_cents) + "</td></tr>" +
  "<tr><td style=\"padding-top:10px;\"><strong>Total</strong></td><td style=\"padding-top:10px; text-align:right;\"><strong>" + money(input.total_cents) + "</strong></td></tr>" +
  "</table>";

return { ...input, cart_html: cart_html };

