const httpResponse = items[0].json;

let paymentUrl = "";
let paymentId = "";

if (httpResponse.payment_link) {
  paymentUrl = httpResponse.payment_link.url || "";
  paymentId = httpResponse.payment_link.id || "";
} else if (httpResponse.body && httpResponse.body.payment_link) {
  paymentUrl = httpResponse.body.payment_link.url || "";
  paymentId = httpResponse.body.payment_link.id || "";
}

const original = items[0].json;

return [{
  json: {
    payment_link_url: paymentUrl,
    payment_link_id: paymentId,
    cart_id: original.cart_id,
    customer_name: original.customer_name,
    customer_email: original.customer_email,
    cart_html: original.cart_html,
    confirmation_email_template: original.confirmation_email_template,
    subtotal_cents: original.subtotal_cents,
    tax_cents: original.tax_cents,
    total_cents: original.total_cents,
    cart_items_json: original.cart_items_json
  }
}];

const input = items[0].json;

if (!input.confirmation_email_template) {
  throw new Error('Missing confirmation_email_template');
}
if (!input.cart_html) {
  throw new Error('Missing cart_html');
}
if (!input.payment_link_url) {
  throw new Error('Missing payment_link_url');
}

let finalEmailHtml = input.confirmation_email_template;

finalEmailHtml = finalEmailHtml.replace(/__CART_HTML__/g, input.cart_html);
finalEmailHtml = finalEmailHtml.replace(
  /__PAYMENT_LINK__/g,
  "<a href=\"" + input.payment_link_url + "\" style=\"background:#8C2F39;color:#ffffff;padding:14px 24px;border-radius:24px;text-decoration:none;font-weight:bold;display:inline-block;\">Complete Payment</a>"
);
finalEmailHtml = finalEmailHtml.replace(/__CURRENT_YEAR__/g, String(new Date().getFullYear()));

const unresolvedTokens = finalEmailHtml.match(/__[^_]+__/g);
if (unresolvedTokens) {
  throw new Error('Unresolved placeholders: ' + unresolvedTokens.join(', '));
}

return [{
  json: {
    ...input,
    final_email_html: finalEmailHtml
  }
}];
